// Coordonnées d'un code postal : { lat, lng } ou null si inconnu
function coordDepuisCP(cp) {
  const e = CODES_POSTAUX[String(cp || '').trim()];
  return e ? { lat: e.lat, lng: e.lng } : null;
}
// Le code postal existe-t-il dans le référentiel belge ?
function cpValide(cp) { return !!CODES_POSTAUX[String(cp || '').trim()]; }
// Infos complètes d'un code postal (nom, province, wallon...)
function infoCP(cp) { return CODES_POSTAUX[String(cp || '').trim()] || null; }
